import { ActionType } from "../../action/action-type";

const initialState = {

    movies: [{ name: "chocho" }

    ],

}

/*************  ✨ Windsurf Command ⭐  *************/
/**
 * Reducer function for managing movie state.
 * It handles FETCH_MOVIES and SELECT_MOVIE actions.
 * If the action type is FETCH_MOVIES, it updates the movie state with the given payload.
 * If the action type is SELECT_MOVIE, it also updates the movie state with the given payload.
 * If the action type is neither FETCH_MOVIES nor SELECT_MOVIE, it returns the current state.
 * @param {object} state - The current state of the application.
 * @param {object} action - The action object containing type and payload.
 * @returns {object} - The new state of the application.
 */
/*******  2b1bc057-cc48-474c-80eb-11f1e663c1ad  *******/
export const movieReducer = (state = initialState, { type, payload }) => {
    switch (type) {
        case ActionType.FETCH_MOVIES:
            return {...initialState, movie: payload };
        case ActionType.SELECT_MOVIE:
            return {...initialState, movie: payload };
        default:
            return state;

    }
}
